
import { describe, it, expect } from 'vitest';
import { calculateGlobalNetworkYield, distributeEdgeworkYield } from '../void-edgework-economy';
import { createObserver } from '../void-game-engine';

describe('void-edgework-economy', () => {
  it('distributes positive sum HEX from edge telemetry', () => {
    const telemetry = {
      activeWorkerNodes: 10,
      packetsRelayed: 100,
      crdtMergesCompleted: 50,
      ucanVerifications: 20
    };
    const globalYield = calculateGlobalNetworkYield(telemetry);
    expect(globalYield).toBe(310);
    
    const obs1 = createObserver('d1', 1, 'mystic', 'scientist', 'boson');
    const result = distributeEdgeworkYield(telemetry, [obs1]);
    expect(result.yieldPerObserver).toBe(310);
    expect(result.updatedObservers[0].energy).toBeGreaterThanOrEqual(100);
  });
});
